previewCss:
.darma-loader-darma-custom-375 {color: var(--loader-color, #0f766e);
  --loader-secondary-color: var(--loader-secondary-color, #5eead4);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.darma-loader-darma-custom-375:before {content: "";
  border: 8px solid var(--loader-color, #0f766e);
  border-radius: 50%;
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: darma-loader-darma-custom-375-l2 infinite 1s steps(4,jump-none);
}@keyframes darma-loader-darma-custom-375-l2 {0% {width: 0% }to {width: 75%}}

